        if (cell.Length == 0)
            throw Empty(table, column);
        if (!float.TryParse(cell, NumberStyles.Float, CultureInfo.InvariantCulture, out var v))
            throw Invalid(table, column, "float", cell);
        CheckRange(v, min, max, table, column);
